import React from 'react';
import { Card, Cards } from '../components/SectionCards';

export default function ContactsPage({ content }) {
    const contacts = content?.contacts || [];
    return (
        <div className="container main">
            <div className="section">
                <h1 className="pageTitle">Contacts</h1>
                {contacts.length ? (
                    <Cards>
                        {contacts.map((c, idx) => (
                            <Card key={`${c.email}-${idx}`} title={c.name} text={c.role} linkUrl={`mailto:${c.email}`} linkLabel={c.email} />
                        ))}
                    </Cards>
                ) : (
                    <p className="muted">Add contacts in `PythonBackend/content.json`.</p>
                )}
            </div>
        </div>
    );
}
